import React, { useState, useEffect } from 'react';

const Trips = () => {
  const [itinerary, setItinerary] = useState([]);
  const [savedItineraries, setSavedItineraries] = useState([]);

  useEffect(() => {
    loadItinerary();
    loadSavedItineraries();
  }, []);

  const loadItinerary = () => {
    const saved = JSON.parse(localStorage.getItem('itinerary') || '[]');
    setItinerary(saved);
  };

  const loadSavedItineraries = () => {
    const saved = JSON.parse(localStorage.getItem('savedItineraries') || '[]');
    setSavedItineraries(saved);
  };

  const deleteItinerary = (id) => {
    if (window.confirm('Are you sure you want to delete this itinerary?')) {
      const updated = savedItineraries.filter(trip => trip.id !== id);
      setSavedItineraries(updated);
      localStorage.setItem('savedItineraries', JSON.stringify(updated));
    }
  };

  const editItinerary = (itinerary) => {
    // Store itinerary data for editing
    localStorage.setItem('editingItinerary', JSON.stringify(itinerary));
    window.location.href = '/budget';
  };

  const removeFromItinerary = (placeId) => {
    const updated = itinerary.filter(place => place.id !== placeId);
    setItinerary(updated);
    localStorage.setItem('itinerary', JSON.stringify(updated));
  };

  const getTotalCost = () => {
    return itinerary.reduce((total, place) => total + parseFloat(place.price), 0);
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>My Trips</h1>
        <a href="/budget" style={styles.createButton}>Create New Trip</a>
      </div>

      {savedItineraries.length > 0 ? (
        <div style={styles.savedSection}>
          <h2 style={styles.sectionTitle}>Saved Itineraries</h2>
          <div style={styles.tableContainer}>
            <table style={styles.table}>
              <thead>
                <tr style={styles.tableHeader}>
                  <th style={styles.th}>Trip Name</th>
                  <th style={styles.th}>City</th>
                  <th style={styles.th}>Duration</th>
                  <th style={styles.th}>Dates</th>
                  <th style={styles.th}>Budget</th>
                  <th style={styles.th}>Total Cost</th>
                  <th style={styles.th}>Places</th>
                  <th style={styles.th}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {savedItineraries.map(trip => (
                  <tr key={trip.id} style={styles.tableRow}>
                    <td style={styles.td}>
                      <strong>{trip.tripName}</strong>
                    </td>
                    <td style={styles.td}>{trip.city}</td>
                    <td style={styles.td}>{trip.days} days</td>
                    <td style={styles.td}>
                      {trip.startDate && trip.endDate ? (
                        <span style={styles.dateText}>
                          {new Date(trip.startDate).toLocaleDateString()} - {new Date(trip.endDate).toLocaleDateString()}
                        </span>
                      ) : 'N/A'}
                    </td>
                    <td style={styles.td}>
                      <span style={styles.budget}>NPR {trip.budget}</span>
                    </td>
                    <td style={styles.td}>
                      <span style={styles.totalCost}>NPR {trip.totalCost}</span>
                    </td>
                    <td style={styles.td}>
                      <span style={styles.placesCount}>{trip.places.length} places</span>
                    </td>
                    <td style={styles.td}>
                      <div style={styles.actionButtons}>
                        <button onClick={() => editItinerary(trip)} style={styles.editButton}>Edit</button>
                        <button onClick={() => deleteItinerary(trip.id)} style={styles.deleteButton}>Delete</button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      ) : (
        <div style={styles.noTrips}>
          <h3>No trips created yet</h3>
          <p>Create your first trip to get started!</p>
          <a href="/budget" style={styles.exploreButton}>Create New Trip</a>
        </div>
      )}
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem',
    backgroundColor: '#f8fafc',
    minHeight: '100vh'
  },
  header: {
    backgroundColor: 'white',
    padding: '2rem',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
    marginBottom: '2rem',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center'
  },
  totalCost: {
    fontSize: '1.5rem',
    fontWeight: '700',
    color: '#059669'
  },
  title: {
    color: '#1f2937',
    fontSize: '2.5rem',
    fontWeight: '700',
    margin: 0
  },
  noTrips: {
    textAlign: 'center',
    padding: '3rem',
    backgroundColor: 'white',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
  },
  exploreButton: {
    backgroundColor: '#3b82f6',
    color: 'white',
    padding: '0.75rem 1.5rem',
    borderRadius: '8px',
    textDecoration: 'none',
    fontWeight: '600',
    display: 'inline-block',
    marginTop: '1rem'
  },
  tripsGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
    gap: '2rem'
  },
  tripCard: {
    backgroundColor: 'white',
    padding: '2rem',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
  },
  tripName: {
    fontSize: '1.25rem',
    fontWeight: '700',
    color: '#1f2937',
    margin: '0 0 1rem 0'
  },
  tripBudget: {
    color: '#059669',
    fontWeight: '600',
    margin: '0 0 0.5rem 0'
  },
  tripDate: {
    color: '#6b7280',
    fontSize: '0.9rem',
    margin: 0
  },
  placeImage: {
    width: '100%',
    height: '150px',
    objectFit: 'cover',
    borderRadius: '8px',
    marginBottom: '1rem'
  },
  cityName: {
    color: '#6b7280',
    fontSize: '0.9rem',
    margin: '0 0 0.5rem 0'
  },
  removeButton: {
    backgroundColor: '#ef4444',
    color: 'white',
    border: 'none',
    padding: '0.5rem 1rem',
    borderRadius: '6px',
    cursor: 'pointer',
    fontSize: '0.9rem',
